sql:
SELECT COUNT(cause_id) 
FROM causes 
WHERE incident_id = 0;

SELECT COUNT(incident_id) AS Count
FROM causes
WHERE cause = 'Gunshot';

external_knowledge:
- "Police brutality" refers to the excessive use of force by law enforcement officers;
- "Unarmed" means the victim was not carrying a weapon;
- "Census tract" is a geographic area defined for demographic data collection.

- A significant poverty rate is defined as greater than 20%;
- Low unemployment rate is defined as less than 10%;
- High number of incidents is defined as more than 10 incidents.

sql:
SELECT cause, COUNT(incident_id) AS incident_count
FROM causes
GROUP BY cause;

external_knowledge:
- 'Residential' refers to incidents that occurred in a home or residential area;
- 'Unarmed' means the victim did not have a weapon;
- 'Black' refers to the race and ethnicity of the victim;
- '1000 sq ft' is a measure of the size of the location.

- "land of prosperity" refers to counties with a higher-than-average income;
- "male souls who fell victim" refers to male victims;
- "sorrows that befell them" refers to the causes of the incidents.

- "more recent incidents" refers to incidents that occurred in or after the year 2015;
- "majority White population" refers to areas where the percentage of the population that is White is greater than 50%;
- "higher average income" refers to areas where the average county income is greater than $50,000.

sql:
SELECT COUNT(incident_id)
FROM incidents
WHERE share_white > (SELECT AVG(share_white) FROM incidents);
